using Microsoft.ML;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

// --- Train the model at startup ---
var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine(app.Environment.ContentRootPath, "Data", "customers.csv");
IDataView dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

// Convert the "Yes"/"No" Label column to boolean
var pipeline = mlContext.Transforms.CustomMapping<CustomerData, LabelMapping>(
        (input, output) => { output.Label = input.Churned; }, contractName: null)
    // One-hot encode the Region text column
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
    // Combine all numeric features into a single vector
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        nameof(CustomerData.PurchaseHistory),
        "RegionEncoded"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var model = pipeline.Fit(dataView);
var predictionEngine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

// --- Endpoints ---
app.MapGet("/", () => "ChurnPredictor API — POST to /predict");

app.MapPost("/predict", (CustomerPredictRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var prediction = predictionEngine.Predict(input);

    return Results.Ok(new
    {
        WillChurn = prediction.WillChurn,
        Probability = prediction.Probability,
        Score = prediction.Score
    });
});

app.Run();

// --- Supporting types ---
public record CustomerPredictRequest(float Age, float Income, string Region, float PurchaseHistory);

// Mapping helper so ML.NET can interpret the Yes/No string as a bool Label
public class LabelMapping
{
    public bool Label { get; set; }
}

